-- dialogs\scriptFilter.lua
L["Unnamed Pets"] = "Mascotas sin nombre"
L["-- Collected pets that still have their original name.\n\nreturn petInfo.isOwned and not petInfo.customName"] = "-- Mascotas recogidas que aún tienen su nombre original.\n\nreturn petInfo.isOwned and not petInfo.customName"
