L["Pets Without Rares"] = "Mascotas sin rarezas"
L["-- Collected battle pets that have no rare version.\n\nif not rares then\n  rares = {}\n  for petID in AllPetIDs() do\n    if select(5,C_PetJournal.GetPetStats(petID))==4 then\n      rares[C_PetJournal.GetPetInfoByPetID(petID)]=true\n    end\n  end\nend\n\nif petInfo.canBattle and petInfo.isOwned and not rares[speciesID] then\n  return true\nend"] = "-- Mascotas de duelo recogidas que no tienen versión rara.\n\nif not rares then\n  rares = {}\n  for petID in AllPetIDs() do\n    if select(5,C_PetJournal.GetPetStats(petID))==4 then\n      rares[C_PetJournal.GetPetInfoByPetID(petID)]=true\n    end\n  end\nend\n\nif petInfo.canBattle and petInfo.isOwned and not rares[speciesID] then\n  return true\nend"
L["Polished Pet Charms"] = "Encantamientos de mascotas pulidos"
L["-- Pets with Polished Pet Charms in their source.\n\nreturn (petInfo.sourceText or \"\"):match(\"item:163036\") and true"] = "-- Mascotas con Encantamientos de Mascotas Pulidos en su origen.\n\nreturn (petInfo.sourceText or \"\"):match(\"item:163036\") and true"
