L["Keep Companion"] = "Mantener compañero"
L["After a team is loaded, summon back the companion that was at your side before the load; or dismiss the pet if you had none summoned."] = "Después de cargar un equipo, invoca de nuevo al compañero que estaba a tu lado antes de la carga; o despide a la mascota si no tenías ninguna invocada."
